"use client";

import { useEffect, useRef, useState } from "react";
import { X, Send } from "lucide-react";
import { Playfair_Display } from "next/font/google";

const playfair = Playfair_Display({
  subsets: ["cyrillic", "latin"],
  weight: ["400", "600", "700", "900"],
});

interface BubbleMessage {
  role: "user" | "assistant";
  content: string;
}

interface MapLocation {
  locationTitle: string;
  lat: number;
  lng: number;
}

interface Props {
  locations: MapLocation[];
}

const REGIONS: Record<string, { center: [number, number]; city: string }> = {
  Минская:     { center: [53.9045, 27.5618], city: "Минск" },
  Брестская:   { center: [52.0976, 23.7341], city: "Брест" },
  Гродненская: { center: [53.6694, 23.8131], city: "Гродно" },
  Витебская:   { center: [55.1848, 30.2016], city: "Витебск" },
  Гомельская:  { center: [52.4412, 30.9878], city: "Гомель" },
  Могилевская: { center: [53.9168, 30.3449], city: "Могилёв" },
};

export default function MapWithAI3D({ locations }: Props) {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef          = useRef<any>(null);
  const initedRef       = useRef(false);
  const chatEndRef      = useRef<HTMLDivElement>(null);

  const [activeRegion, setActiveRegion] = useState<string | null>(null);
  const [messages, setMessages]         = useState<BubbleMessage[]>([]);
  const [input, setInput]               = useState("");
  const [loading, setLoading]           = useState(false);
  const [is3D, setIs3D]                 = useState(false);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  useEffect(() => {
    if (!mapContainerRef.current || initedRef.current) return;
    initedRef.current = true;

    const key = process.env.NEXT_PUBLIC_MAPTILER_KEY;

    import("maplibre-gl").then((maplibre) => {
      const L = maplibre;

      if (!document.getElementById("maplibre-css")) {
        const link = document.createElement("link");
        link.id = "maplibre-css";
        link.rel = "stylesheet";
        link.href = "https://cdn.jsdelivr.net/npm/maplibre-gl@3.6.2/dist/maplibre-gl.css";
        document.head.appendChild(link);
      }

      const map = new L.Map({
        container: mapContainerRef.current!,
        style: `https://api.maptiler.com/maps/satellite/style.json?key=${key}`,
        center: [27.5, 53.5],
        zoom: 6.5,
        pitch: 0,
        bearing: 0,
      } as any);

      mapRef.current = map;

      map.on("load", () => {

        // 3D рельеф
        map.addSource("terrain", {
          type: "raster-dem",
          url: `https://api.maptiler.com/tiles/terrain-rgb-v2/tiles.json?key=${key}`,
          tileSize: 256,
        });
        map.setTerrain({ source: "terrain", exaggeration: 1.8 });

        // Небо
        map.addLayer({
          id: "sky",
          type: "sky",
          paint: {
            "sky-type": "atmosphere",
            "sky-atmosphere-sun": [0.0, 90.0],
            "sky-atmosphere-sun-intensity": 15,
          },
        } as any);

        // Загружаем точный GeoJSON из public/
        fetch("/belarus.geojson")
          .then(r => r.json())
          .then(belarus => {

            const rings = belarus.geometry.type === "Polygon"
              ? belarus.geometry.coordinates
              : belarus.geometry.coordinates.flat(1);

            // Маска — затемняем всё кроме Беларуси
            const mask = {
              type: "Feature",
              properties: {},
              geometry: {
                type: "Polygon",
                coordinates: [
                  [[-180,-90],[180,-90],[180,90],[-180,90],[-180,-90]],
                  ...rings,
                ],
              },
            };

            map.addSource("belarus-mask", {
              type: "geojson",
              data: mask as any,
            });

            map.addLayer({
              id: "belarus-mask-layer",
              type: "fill",
              source: "belarus-mask",
              paint: {
                "fill-color": "#000000",
                "fill-opacity": 0.75,
              },
            });

            // Граница — 3 слоя
            map.addSource("belarus-border", {
              type: "geojson",
              data: belarus,
            });

            map.addLayer({
              id: "belarus-border-glow",
              type: "line",
              source: "belarus-border",
              paint: {
                "line-color": "rgba(255,255,255,0.15)",
                "line-width": 12,
                "line-blur": 8,
              },
            });

            map.addLayer({
              id: "belarus-border-mid",
              type: "line",
              source: "belarus-border",
              paint: {
                "line-color": "rgba(255,255,255,0.5)",
                "line-width": 4,
                "line-blur": 2,
              },
            });

            map.addLayer({
              id: "belarus-border-sharp",
              type: "line",
              source: "belarus-border",
              paint: {
                "line-color": "rgba(255,255,255,0.95)",
                "line-width": 1.5,
              },
            });
          })
          .catch(e => console.error("Belarus GeoJSON error:", e));

        // Маркеры посещённых мест
        locations.forEach((loc) => {
          if (!loc.lat || !loc.lng) return;
          const el = document.createElement("div");
          el.style.cssText = `
            width:10px;height:10px;border-radius:50%;
            background:rgba(255,255,255,0.9);
            border:2px solid white;
            box-shadow:0 0 8px rgba(0,0,0,0.5);
            cursor:pointer;
          `;
          new L.Marker({ element: el })
            .setLngLat([loc.lng, loc.lat])
            .addTo(map);
        });

        // Пины регионов
        Object.entries(REGIONS).forEach(([region, { center }]) => {
          const el = document.createElement("div");
          el.style.cssText = "display:flex;flex-direction:column;align-items:center;cursor:pointer;";
          el.innerHTML = `
            <div class="pin-ring" style="
              width:22px;height:22px;border-radius:50%;
              background:rgba(255,255,255,0.85);
              border:2px solid rgba(255,255,255,0.95);
              box-shadow:0 0 0 4px rgba(255,255,255,0.2),0 4px 16px rgba(0,0,0,0.5);
              transition:transform 0.2s,box-shadow 0.2s;
            "></div>
            <div style="
              margin-top:5px;
              color:rgba(255,255,255,0.95);
              font-size:11px;
              font-family:serif;
              letter-spacing:0.08em;
              text-shadow:0 1px 4px rgba(0,0,0,0.9),0 0 8px rgba(0,0,0,0.6);
              white-space:nowrap;
              pointer-events:none;
            ">${region}</div>
          `;

          el.addEventListener("mouseenter", () => {
            const ring = el.querySelector(".pin-ring") as HTMLElement;
            if (ring) ring.style.transform = "scale(1.3)";
          });
          el.addEventListener("mouseleave", () => {
            const ring = el.querySelector(".pin-ring") as HTMLElement;
            if (ring) ring.style.transform = "scale(1)";
          });
          el.addEventListener("click", () => {
            map.flyTo({
              center: [center[1], center[0]],
              zoom: 11,
              pitch: 60,
              bearing: -20,
              duration: 2500,
            } as any);
            setIs3D(true);
            openPanel(region);
          });

          new L.Marker({ element: el })
            .setLngLat([center[1], center[0]])
            .addTo(map);
        });
      });
    });

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
        initedRef.current = false;
      }
    };
  }, []);

  const resetView = () => {
    if (!mapRef.current) return;
    mapRef.current.flyTo({
      center: [27.5, 53.5],
      zoom: 6.5,
      pitch: 0,
      bearing: 0,
      duration: 1800,
    } as any);
    setIs3D(false);
  };

  const openPanel = (region: string) => {
    setActiveRegion(region);
    setMessages([]);
    setInput("");
    fetchAI(region);
  };

  const closePanel = () => {
    setActiveRegion(null);
    setMessages([]);
    resetView();
  };

  const fetchAI = async (region: string) => {
    setLoading(true);
    try {
      const res = await fetch("/api/ai-assistant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: `Расскажи про ${region} область Беларуси. Ответь строго по шаблону:

🏆 Главная фишка: [одно предложение — что делает эту область уникальной]

📍 Топ-3 места:
- [название] — [5-7 слов почему стоит посетить]
- [название] — [5-7 слов почему стоит посетить]
- [название] — [5-7 слов почему стоит посетить]

❓ [Один вопрос про интересы туриста]`,
        }),
      });
      const data = await res.json();
      const content = data.response?.message ?? (typeof data.response === "string" ? data.response : "Не удалось загрузить 😔");
      setMessages([{ role: "assistant", content }]);
    } catch {
      setMessages([{ role: "assistant", content: "Не удалось загрузить 😔" }]);
    } finally {
      setLoading(false);
    }
  };

  const sendMessage = async () => {
    if (!input.trim() || loading || !activeRegion) return;
    const text = input;
    setMessages((prev) => [...prev, { role: "user", content: text }]);
    setInput("");
    setLoading(true);
    try {
      const res = await fetch("/api/ai-assistant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: `[${activeRegion} область Беларуси] ${text}` }),
      });
      const data = await res.json();
      const content = data.response?.message ?? (typeof data.response === "string" ? data.response : "Ошибка 😔");
      setMessages((prev) => [...prev, { role: "assistant", content }]);
    } catch {
      setMessages((prev) => [...prev, { role: "assistant", content: "Ошибка соединения 😔" }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="relative w-full h-full flex overflow-hidden">

      <div style={{
        flex: activeRegion ? "0 0 58%" : "1",
        transition: "flex 0.4s cubic-bezier(0.4,0,0.2,1)",
        position: "relative",
      }}>
        <div ref={mapContainerRef} className="w-full h-full" />

        <div className="absolute inset-0 pointer-events-none" style={{
          background: "radial-gradient(ellipse at center, transparent 50%, rgba(0,0,0,0.4) 100%)"
        }} />

        {is3D && (
          <button
            onClick={resetView}
            className="absolute top-3 right-3 z-10 bg-black/40 backdrop-blur-sm text-white text-xs px-3 py-1.5 rounded-full border border-white/20 hover:bg-black/60 transition"
          >
            ← Беларусь
          </button>
        )}
      </div>

      {activeRegion && (
        <div style={{
          flex: "0 0 42%",
          background: "#f5f0e8",
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
          animation: "panelSlide 0.4s cubic-bezier(0.4,0,0.2,1) both",
        }}>
          <style>{`
            @keyframes panelSlide {
              from { opacity:0; transform:translateX(20px); }
              to   { opacity:1; transform:translateX(0); }
            }
          `}</style>

          <div className="flex items-center justify-between px-8 py-5" style={{ background: "#2d4a2d" }}>
            <span className={`${playfair.className} text-white text-sm font-semibold tracking-widest uppercase`}>
              {activeRegion} область
            </span>
            <button onClick={closePanel} className="text-white/60 hover:text-white transition">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto px-8 py-6">
            {loading && messages.length === 0 && (
              <div className="space-y-3">
                {[0.75, 1, 0.83, 0.67, 1, 0.8].map((w, i) => (
                  <div key={i} className="h-4 bg-gray-200 rounded animate-pulse" style={{ width: `${w * 100}%` }} />
                ))}
              </div>
            )}

            {messages.map((msg, i) => (
              <div key={i} className={`mb-4 ${msg.role === "user" ? "flex justify-end" : ""}`}>
                {msg.role === "assistant" ? (
                  <div>
                    <p className={`${playfair.className} text-2xl font-bold text-gray-900 mb-4`}>
                      {activeRegion}
                    </p>
                    <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">
                      {msg.content}
                    </p>
                  </div>
                ) : (
                  <div className="bg-gray-900 text-white text-sm px-4 py-2.5 rounded-2xl rounded-br-sm max-w-[85%]">
                    {msg.content}
                  </div>
                )}
              </div>
            ))}

            {loading && messages.length > 0 && (
              <div className="flex gap-1.5 py-2">
                {[0, 150, 300].map((d) => (
                  <div key={d} className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: `${d}ms` }} />
                ))}
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          <div className="px-6 py-4 border-t border-gray-200 bg-white/50">
            <div className="flex gap-2">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && sendMessage()}
                placeholder="Спроси про регион..."
                disabled={loading}
                className="flex-1 text-sm px-4 py-2.5 bg-white border border-gray-200 rounded-full focus:outline-none focus:border-gray-400 transition disabled:opacity-50"
              />
              <button
                onClick={sendMessage}
                disabled={loading || !input.trim()}
                className="w-9 h-9 rounded-full flex items-center justify-center text-white transition disabled:opacity-40"
                style={{ background: "#2d4a2d" }}
              >
                <Send className="w-3.5 h-3.5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}